using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver — resolves any type.
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1️⃣ GetTypeInfo<T>() — strongly-typed metadata access
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned metadata for: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2️⃣ TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded: {info!.Type.Name}");
}

// Now demonstrate the "not available" path.
// A source-gen context that only knows about Person — UnknownType won't resolve.
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = PersonContext.Default
};

if (restrictedOptions.TryGetTypeInfo<UnknownType>(out JsonTypeInfo<UnknownType>? missing))
{
    Console.WriteLine($"Resolved UnknownType: {missing!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<UnknownType> returned false — no exception thrown.");
}

// Types used in the demo
public record Person(string Name, int Age);
public class UnknownType { public int X { get; set; } }

[JsonSerializable(typeof(Person))]
public partial class PersonContext : JsonSerializerContext;

